import { NextResponse } from "next/server";
import { db } from "@/lib/firebase-admin";

export async function POST(req: Request) {
  try {
    const expenseData = await req.json();

    if (!expenseData || !expenseData.amount) {
      return NextResponse.json({ error: "Invalid expense data" }, { status: 400 });
    }

    // Add the createdAt timestamp server-side
    const docRef = await db.collection('expenses').add({
      ...expenseData,
      createdAt: new Date(),
    });

    return NextResponse.json({ success: true, id: docRef.id, ...expenseData });
  } catch (error: any) {
    console.error("Error saving expense to admin SDK:", error);
    return NextResponse.json({ error: error.message || "Failed to save expense securely" }, { status: 500 });
  }
}
